#include <iostream>

class Tracker {
public:
    Tracker(int id) : m_id{id} {
        std::cout << "open " << m_id << '\n';
    }
    ~Tracker() {
        std::cout << "close " << m_id << '\n';
    }
private:
    int m_id;
};

int main() {
    int a, b;
    std::cin >> a >> b;
    Tracker t1{a};
    Tracker t2{b};
    return 0;
}

