solution_code:
#include <iostream>
#include <string>

class ScopedLog {
public:
    ScopedLog(const std::string& name) : m_name{name} {
        std::cout << '[' << m_name << "] start\n";
    }
    ~ScopedLog() {
        std::cout << '[' << m_name << "] end\n";
    }
private:
    std::string m_name;
};

int main() {
    std::string name;
    std::cin >> name;
    ScopedLog log{name};
    std::cout << '[' << name << "] working\n";
    return 0;
}
